1	\chapter{Mayer--Vietoris long exact sequence for sheaf cohomology with $k$-module coefficients}
2	\label{chap:Cohomology_MayerVietoris}
3	
4	This chapter constructs the Mayer--Vietoris long exact sequence for sheaf cohomology valued in $k$-modules, and develops the \v{C}ech-acyclicity machinery for affine basic-open covers. Together these provide the categorical engine for the Serre finiteness argument (Phase~A step~6). The carriers $H^n(X,\mathcal F)$ and $H^{\prime n}(U,\mathcal F)$ live in Chapter~\ref{chap:Cohomology_StructureSheafModuleK} and are imported here.
5	
6	The chapter introduces no protected declarations: every definition, lemma, and instance here is auxiliary, supporting the construction of $H^1(C,\mathcal O_C)$ in Definition~\ref{def:genus}.
7	
8	\section{Functoriality of cohomology in the open variable}
9	\label{sec:hmodule_prime_cohomologyPresheaf}
10	
11	The cohomology-of-an-open carrier $H^{\prime n}(X,\mathcal F)$ is contravariantly functorial in the open variable $X$. Assembling this functoriality yields a presheaf
12	\[
13	  X \longmapsto H^{\prime n}(X, \mathcal F),
14	\]
15	and, varying $\mathcal F$ as well, a bifunctor from sheaves of $k$-modules to presheaves of abelian groups. The codomain is the category of abelian groups because $\Ext$ is always valued there, regardless of the linear enrichment of the source category; the per-fiber $k$-module structure is inherited from the reducible wrapper on $H^{\prime n}$.
16	
17	\begin{definition}\leanok
18	[Cohomology presheaf functor, $H'$ flavor]
19	  \label{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
20	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheafFunctor}
21	  \uses{def:Scheme_HModule_prime, thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
22	  Let $k$ be a field, $C$ a category equipped with a Grothendieck topology $J$, and assume sheafification and $\Ext$ exist for sheaves of $k$-modules on $J$. For $n \in \mathbb N$, define the cohomology presheaf functor
23	  \[
24	    \mathcal H^{\prime n}(k, J) \;:\; \Sheaf\,J\,(\ModuleCat\,k) \longrightarrow (C^{\op} \longrightarrow \AddCommGrpCat)
25	  \]
26	  by the standard composition of the Yoneda embedding, the free-$k$-module functor, sheafification, and the $n$-th $\Ext$ functor.
27	\end{definition}
28	
29	\begin{proof}
30	  \uses{def:Scheme_HModule_prime}
31	  \leanok
32	  The body is a direct categorical composition mirroring the general sheaf-cohomology presheaf functor. Universe pinning is required because the morphism universe of the sheaf category lives one level above the object universe.
33	\end{proof}
34	
35	\begin{definition}\leanok
36	[Cohomology presheaf, $H'$ flavor]
37	  \label{def:Scheme_HModule_prime_cohomologyPresheaf}
38	  \lean{AlgebraicGeometry.Scheme.HModule'_cohomologyPresheaf}
39	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
40	  In the setting of Definition~\ref{def:Scheme_HModule_prime_cohomologyPresheafFunctor}, let $\mathcal F$ be a sheaf of $k$-modules. For $n \in \mathbb N$, define the cohomology presheaf
41	  \[
42	    \mathcal H^{\prime n}(\mathcal F) \;:\; C^{\op} \longrightarrow \AddCommGrpCat
43	  \]
44	  to be the evaluation of the bifunctor at $\mathcal F$.
45	\end{definition}
46	
47	\begin{proof}
48	  \uses{def:Scheme_HModule_prime_cohomologyPresheafFunctor}
49	  \leanok
50	  Direct evaluation of the bifunctor at $\mathcal F$.
51	\end{proof}
52	
53	\begin{remark}
54	  For every object $X$ of $C$, the underlying type of $\mathcal H^{\prime n}(\mathcal F)(X)$ is definitionally equal to $H^{\prime n}(X, \mathcal F)$. The per-fiber $k$-module structure is therefore inherited through the $H'$ wrapper.
55	\end{remark}
56	
57	\begin{remark}[Lean implementation]
58	  The cohomology presheaf functor is declared as a non-computable definition and the presheaf as a non-computable abbrev, matching the reducibility conventions of the general sheaf-cohomology API. The abbrev form is load-bearing: downstream definitional unfolding needs to see through to the fiber-level $H'$ carrier.
59	\end{remark}
60	
61	\section{Mayer--Vietoris long exact sequence}
62	\label{sec:hmodule_prime_mayer_vietoris}
63	
64	A Mayer--Vietoris square for a Grothendieck topology $J$ on a category $C$ is a pullback square
65	\[
66	  \begin{tikzcd}
67	    X_1 \ar[r] \ar[d] & X_2 \ar[d] \\
68	    X_3 \ar[r] & X_4
69	  \end{tikzcd}
70	\]
71	that is a $J$-cover: the pair of morphisms $X_2 \to X_4$ and $X_3 \to X_4$ is a covering family, and $X_1$ is the pullback. For a sheaf $\mathcal F$, the cohomology groups of the four corners are linked by a long exact sequence whose building blocks are restriction maps, biproduct maps, and a connecting homomorphism.
72	
73	\subsection{The restriction maps}
74	
75	\begin{definition}\leanok
76	[Sum of two restriction maps]
77	  \label{def:Scheme_HModule_prime_toBiprod}
78	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
79	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
80	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n \in \mathbb N$. Define the morphism
81	  \[
82	    \toBiprod \;:\; H^{\prime n}(X_4, \mathcal F) \longrightarrow H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F)
83	  \]
84	  to be the biproduct lift of the two restriction maps induced by $X_2 \to X_4$ and $X_3 \to X_4$.
85	\end{definition}
86	
87	\begin{proof}
88	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
89	  \leanok
90	  The biproduct exists because the category of abelian groups has finite biproducts. The morphism is built from the contravariant functoriality of the cohomology presheaf.
91	\end{proof}
92	
93	\begin{definition}\leanok
94	[Difference of two restriction maps]
95	  \label{def:Scheme_HModule_prime_fromBiprod}
96	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod}
97	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
98	  In the same setting, define the morphism
99	  \[
100	    \fromBiprod \;:\; H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F) \longrightarrow H^{\prime n}(X_1, \mathcal F)
101	  \]
102	  to be the biproduct desc of the restriction map $X_1 \to X_2$ and the additive inverse of the restriction map $X_1 \to X_3$.
103	\end{definition}
104	
105	\begin{proof}
106	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf}
107	  \leanok
108	  The negation is taken in the preadditive morphism group of the codomain category. The sign convention encodes the alternating-sum structure of the \v{C}ech complex.
109	\end{proof}
110	
111	\begin{lemma}\leanok
112	[Composition vanishes]
113	  \label{lem:Scheme_HModule_prime_toBiprod_fromBiprod}
114	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_fromBiprod}
115	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
116	  In the setting above,
117	  \[
118	    \fromBiprod \circ \toBiprod \;=\; 0.
119	  \]
120	\end{lemma}
121	
122	\begin{proof}
123	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod}
124	  \leanok
125	  This is a formal consequence of the biproduct universal property, preadditivity, and the pullback equation $X_1 \to X_2 \to X_4 = X_1 \to X_3 \to X_4$. Every step is independent of the value category and transfers verbatim from the abelian-group-valued setting.
126	\end{proof}
127	
128	\subsection{The short exact sequence of sheaves}
129	
130	The connecting homomorphism of the Mayer--Vietoris sequence is built from a short exact sequence of sheaves of $k$-modules obtained by sheafifying the Yoneda embedding composed with the free-$k$-module functor.
131	
132	\begin{definition}\leanok
133	[Free-$k$-module functor is left adjoint]
134	  \label{def:Scheme_ModuleCat_free_isLeftAdjoint}
135	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_isLeftAdjoint}
136	  \uses{}
137	  Let $k$ be a field. The free-$k$-module functor $\Type \to \ModuleCat\,k$ is a left adjoint.
138	\end{definition}
139	
140	\begin{proof}
141	  \uses{}
142	  \leanok
143	  The adjunction is the standard free-forgetful adjunction for $k$-modules. The declaration packages the existing adjunction into the typeclass-witness form.
144	\end{proof}
145	
146	\begin{lemma}\leanok
147	[Pushout of free sheaves]
148	  \label{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
149	  \lean{AlgebraicGeometry.Scheme.HModule'_isPushoutModuleCatFreeSheaf}
150	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
151	  Let $S$ be a Mayer--Vietoris square. The image of $S$ under the composite functor
152	  \[
153	    \text{Yoneda} \;\circ\; \text{whiskering with }(\ModuleCat.\free\,k) \;\circ\; \presheafToSheaf
154	  \]
155	  is a pushout square in the category of sheaves of $k$-modules.
156	\end{lemma}
157	
158	\begin{proof}
159	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint}
160	  \leanok
161	  The original square is a pushout. Post-composition with the sheafify-compose functor preserves pushouts because the free-$k$-module functor is a left adjoint. A canonical isomorphism translates the resulting square into the desired shape.
162	\end{proof}
163	
164	\begin{definition}\leanok
165	[Short complex of free sheaves]
166	  \label{def:Scheme_HModule_prime_shortComplex}
167	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex}
168	  \uses{def:Scheme_ModuleCat_free_isLeftAdjoint, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
169	  In the setting of Lemma~\ref{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}, define the short complex of sheaves of $k$-modules
170	  \[
171	    \mathcal F_1 \xrightarrow{\;f\;} \mathcal F_2 \oplus \mathcal F_3 \xrightarrow{\;g\;} \mathcal F_4,
172	  \]
173	  where $f$ is the biproduct lift of the two maps induced by $X_1 \to X_2$ and $-X_1 \to X_3$, and $g$ is the biproduct desc of the two maps induced by $X_2 \to X_4$ and $X_3 \to X_4$. The composition $g \circ f = 0$ follows from the cokernel-cofork condition of the pushout.
174	\end{definition}
175	
176	\begin{proof}
177	  \uses{lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
178	  \leanok
179	  The five object and morphism fields are filled directly from the pushout data; the zero field follows from the cokernel cofork condition.
180	\end{proof}
181	
182	\begin{definition}\leanok
183	[Free-$k$-module functor preserves monomorphisms]
184	  \label{def:Scheme_ModuleCat_free_preservesMonomorphisms}
185	  \lean{AlgebraicGeometry.Scheme.ModuleCat_free_preservesMonomorphisms}
186	  \uses{}
187	  Let $k$ be a field. The free-$k$-module functor preserves monomorphisms.
188	\end{definition}
189	
190	\begin{proof}
191	  \uses{}
192	  \leanok
193	  An injective function between types induces an injective $k$-linear map on free modules because the map on finsupp supports is injective. Monomorphism status in the category of $k$-modules is equivalent to injectivity.
194	\end{proof}
195	
196	\begin{lemma}\leanok
197	[The first map is mono]
198	  \label{lem:Scheme_HModule_prime_shortComplex_f_mono}
199	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_f_mono}
200	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
201	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, the first map $f$ is a monomorphism.
202	\end{lemma}
203	
204	\begin{proof}
205	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms}
206	  \leanok
207	  The map $f$ followed by the second projection is the free-$k$-module functor applied to the monomorphism $X_1 \to X_3$, which is mono because the free functor preserves monomorphisms. Hence $f$ itself is mono.
208	\end{proof}
209	
210	\begin{lemma}\leanok
211	[The second map is epi]
212	  \label{lem:Scheme_HModule_prime_shortComplex_g_epi}
213	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_g_epi}
214	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
215	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, the second map $g$ is an epimorphism.
216	\end{lemma}
217	
218	\begin{proof}
219	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
220	  \leanok
221	  By the pushout lemma, $g$ is the cokernel of $f$, and every cokernel is epi.
222	\end{proof}
223	
224	\begin{lemma}\leanok
225	[Exactness at the middle term]
226	  \label{lem:Scheme_HModule_prime_shortComplex_exact}
227	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_exact}
228	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
229	  In the short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex}, exactness holds at the middle term: the image of $f$ equals the kernel of $g$.
230	\end{lemma}
231	
232	\begin{proof}
233	  \uses{def:Scheme_HModule_prime_shortComplex, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
234	  \leanok
235	  By the pushout lemma, $g$ is the cokernel of $f$; a map is its own kernel's cokernel in an abelian category, so exactness holds at the middle term.
236	\end{proof}
237	
238	\begin{lemma}\leanok
239	[The short complex is short exact]
240	  \label{lem:Scheme_HModule_prime_shortComplex_shortExact}
241	  \lean{AlgebraicGeometry.Scheme.HModule'_shortComplex_shortExact}
242	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
243	  The short complex of Definition~\ref{def:Scheme_HModule_prime_shortComplex} is short exact: its first map is mono, its second map is epi, and exactness holds at the middle term.
244	\end{lemma}
245	
246	\begin{proof}
247	  \uses{def:Scheme_HModule_prime_shortComplex, def:Scheme_ModuleCat_free_preservesMonomorphisms, lem:Scheme_HModule_prime_isPushoutModuleCatFreeSheaf}
248	  \leanok
249	  Combine Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_f_mono}, Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_g_epi}, and Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_exact}.
250	\end{proof}
251	
252	\subsection{The connecting homomorphism and the long exact sequence}
253	
254	\begin{definition}\leanok
255	[Connecting homomorphism]
256	  \label{def:Scheme_HModule_prime_delta}
257	  \lean{AlgebraicGeometry.Scheme.HModule'_δ}
258	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf, lem:Scheme_HModule_prime_shortComplex_shortExact}
259	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n_0, n_1 \in \mathbb N$ with $n_0 + 1 = n_1$. The connecting homomorphism
260	  \[
261	    \delta \;:\; H^{\prime n_0}(X_1, \mathcal F) \longrightarrow H^{\prime n_1}(X_4, \mathcal F)
262	  \]
263	  is obtained by precomposing the extension class of the short exact sequence of Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_shortExact} with the canonical degree-zero map.
264	\end{definition}
265	
266	\begin{proof}
267	  \uses{def:Scheme_HModule_prime_cohomologyPresheaf, lem:Scheme_HModule_prime_shortComplex_shortExact}
268	  \leanok
269	  The extension class lives in $\Ext^1$ of the short exact sequence; precomposing with a map of degree zero and transporting through the additive structure yields the connecting homomorphism as a morphism of abelian groups.
270	\end{proof}
271	
272	\begin{definition}\leanok
273	[Mayer--Vietoris long exact sequence]
274	  \label{def:Scheme_HModule_prime_sequence}
275	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence}
276	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_delta}
277	  In the setting of Definition~\ref{def:Scheme_HModule_prime_delta}, define the five-term Mayer--Vietoris sequence
278	  \[
279	    H^{\prime n_0}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_0}(X_2, \mathcal F) \oplus H^{\prime n_0}(X_3, \mathcal F) \xrightarrow{\;\fromBiprod\;} H^{\prime n_0}(X_1, \mathcal F) \xrightarrow{\;\delta\;} H^{\prime n_1}(X_4, \mathcal F) \xrightarrow{\;\toBiprod\;} H^{\prime n_1}(X_2, \mathcal F) \oplus H^{\prime n_1}(X_3, \mathcal F).
280	  \]
281	\end{definition}
282	
283	\begin{proof}
284	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_delta}
285	  \leanok
286	  The sequence is packaged as five composable arrows in the category of abelian groups.
287	\end{proof}
288	
289	\subsection{Comparison with the $\Ext$ contravariant sequence}
290	
291	The following four lemmas bridge the biproduct structure on the abelian-group side with the $\Ext$ biproduct additivity, preparing the comparison isomorphism.
292	
293	\begin{lemma}\leanok
294	[Elementwise formula for $\toBiprod$]
295	  \label{lem:Scheme_HModule_prime_toBiprod_apply}
296	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_apply}
297	  \uses{def:Scheme_HModule_prime_toBiprod}
298	  For $y \in H^{\prime n}(X_4, \mathcal F)$,
299	  \[
300	    \toBiprod(y) \;=\; \bigl(\mathrm{restriction}_{X_4 \to X_2}(y),\; \mathrm{restriction}_{X_4 \to X_3}(y)\bigr).
301	  \]
302	\end{lemma}
303	
304	\begin{proof}
305	  \uses{def:Scheme_HModule_prime_toBiprod}
306	  \leanok
307	  Follows from the definition of $\toBiprod$ as a biproduct lift and the naturality of the biproduct isomorphism with the product.
308	\end{proof}
309	
310	\begin{lemma}\leanok
311	[Elementwise formula for $\fromBiprod$]
312	  \label{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply}
313	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_biprodIsoProd_inv_apply}
314	  \uses{def:Scheme_HModule_prime_fromBiprod}
315	  For $y_2 \in H^{\prime n}(X_2, \mathcal F)$ and $y_3 \in H^{\prime n}(X_3, \mathcal F)$,
316	  \[
317	    \fromBiprod(y_2, y_3) \;=\; \mathrm{restriction}_{X_2 \to X_1}(y_2) \;-\; \mathrm{restriction}_{X_3 \to X_1}(y_3).
318	  \]
319	\end{lemma}
320	
321	\begin{proof}
322	  \uses{def:Scheme_HModule_prime_fromBiprod}
323	  \leanok
324	  Follows from the definition of $\fromBiprod$ as a biproduct desc and the concrete description of the biproduct isomorphism.
325	\end{proof}
326	
327	\begin{lemma}\leanok
328	[$\Ext$ biproduct bridge for $\toBiprod$]
329	  \label{lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply}
330	  \lean{AlgebraicGeometry.Scheme.HModule'_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply}
331	  \uses{def:Scheme_HModule_prime_toBiprod, def:Scheme_HModule_prime_shortComplex}
332	  Bridges the abelian-group biproduct isomorphism and the $\Ext$ biproduct additivity for the $\toBiprod$ morphism.
333	\end{lemma}
334	
335	\begin{proof}
336	  \uses{lem:Scheme_HModule_prime_toBiprod_apply}
337	  \leanok
338	  Injects through the additive equivalence and closes by categorical discharge.
339	\end{proof}
340	
341	\begin{lemma}\leanok
342	[$\Ext$ biproduct bridge for $\fromBiprod$]
343	  \label{lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
344	  \lean{AlgebraicGeometry.Scheme.HModule'_mk₀_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
345	  \uses{def:Scheme_HModule_prime_fromBiprod, def:Scheme_HModule_prime_shortComplex}
346	  Bridges the same machinery for the $\fromBiprod$ morphism.
347	\end{lemma}
348	
349	\begin{proof}
350	  \uses{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply}
351	  \leanok
352	  Obtains a pair from the biproduct surjectivity, then rewrites through the concrete formulas and closes by categorical discharge.
353	\end{proof}
354	
355	\begin{definition}\leanok
356	[Comparison isomorphism]
357	  \label{def:Scheme_HModule_prime_sequenceIso}
358	  \lean{AlgebraicGeometry.Scheme.HModule'_sequenceIso}
359	  \uses{def:Scheme_HModule_prime_sequence, lem:Scheme_HModule_prime_shortComplex_shortExact, lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply, lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
360	  The Mayer--Vietoris sequence of Definition~\ref{def:Scheme_HModule_prime_sequence} is canonically isomorphic to the $\Ext$ contravariant sequence applied to the short exact sequence of Lemma~\ref{lem:Scheme_HModule_prime_shortComplex_shortExact}.
361	\end{definition}
362	
363	\begin{proof}
364	  \uses{lem:Scheme_HModule_prime_biprodAddEquiv_symm_biprodIsoProd_hom_toBiprod_apply, lem:Scheme_HModule_prime_mk_zero_f_comp_biprodAddEquiv_symm_biprodIsoProd_hom}
365	  \leanok
366	  The isomorphism is built componentwise: identity maps on the bare terms, and the composition of the biproduct isomorphism with the $\Ext$ biproduct additivity (in the appropriate direction) on the biproduct terms. The five compatibility squares close via the four auxiliary lemmas above and the definition of the connecting homomorphism.
367	\end{proof}
368	
369	\subsection{Exactness}
370	
371	\begin{theorem}\leanok
372	[Mayer--Vietoris exactness]
373	  \label{thm:Scheme_HModule_prime_sequence_exact}
374	  \lean{AlgebraicGeometry.Scheme.HModule'_sequence_exact}
375	  \uses{def:Scheme_HModule_prime_sequence, def:Scheme_HModule_prime_sequenceIso}
376	  The Mayer--Vietoris sequence of Definition~\ref{def:Scheme_HModule_prime_sequence} is exact.
377	\end{theorem}
378	
379	\begin{proof}
380	  \uses{def:Scheme_HModule_prime_sequenceIso}
381	  \leanok
382	  Transport exactness along the comparison isomorphism of Definition~\ref{def:Scheme_HModule_prime_sequenceIso}. The $\Ext$ contravariant sequence is exact by the general exactness theorem for $\Ext$ applied to a short exact sequence.
383	\end{proof}
384	
385	\begin{lemma}\leanok
386	[Connecting homomorphism annihilates $\toBiprod$]
387	  \label{lem:Scheme_HModule_prime_delta_toBiprod}
388	  \lean{AlgebraicGeometry.Scheme.HModule'_δ_toBiprod}
389	  \uses{thm:Scheme_HModule_prime_sequence_exact}
390	  In the setting above,
391	  \[
392	    \delta \circ \toBiprod \;=\; 0.
393	  \]
394	\end{lemma}
395	
396	\begin{proof}
397	  \uses{thm:Scheme_HModule_prime_sequence_exact}
398	  \leanok
399	  Immediate from exactness at the third term of the sequence.
400	\end{proof}
401	
402	\begin{lemma}\leanok
403	[$\fromBiprod$ annihilates the connecting homomorphism]
404	  \label{lem:Scheme_HModule_prime_fromBiprod_delta}
405	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_δ}
406	  \uses{thm:Scheme_HModule_prime_sequence_exact}
407	  In the setting above,
408	  \[
409	    \fromBiprod \circ \delta \;=\; 0.
410	  \]
